import { defineConfig } from 'astro/config';
import sitemap from '@astrojs/sitemap';
import sanity from '@sanity/astro';
import react from '@astrojs/react';
import vercel from '@astrojs/vercel';

export default defineConfig({
  site: 'https://ficcc.org',
  // Astro 5 removed output:'hybrid' — static + adapter is the equivalent,
  // enabling per-page SSR opt-in via `export const prerender = false`.
  output: 'static', // hybrid equivalent with adapter
  adapter: vercel(),
  integrations: [
    sitemap(),
    sanity({
      projectId: import.meta.env.SANITY_PROJECT_ID || 'placeholder',
      dataset: import.meta.env.SANITY_DATASET || 'production',
      useCdn: false, // false for static builds per @sanity/astro docs
      stega: {
        studioUrl: import.meta.env.PUBLIC_SANITY_PREVIEW_URL || 'http://localhost:3333',
      },
    }),
    react(),
  ],
  i18n: {
    defaultLocale: 'en',
    locales: ['en', 'zh'],
    routing: {
      prefixDefaultLocale: false,
    },
  },
});

---
interface Props {
  title: string;
  description?: string;
  canonicalUrl?: string;
  ogImage?: string;
  ogType?: string;
  lang?: string;
  jsonLd?: Record<string, unknown>;
  alternateUrl?: string;
}

const {
  title,
  description = 'A Chinese-heritage, university-adjacent Christian community in Ithaca, NY.',
  canonicalUrl,
  ogImage = '/og-default.png',
  ogType = 'website',
  lang = 'en',
  jsonLd,
  alternateUrl,
} = Astro.props;

const siteUrl = Astro.site ?? new URL('https://ficcc.org');
const canonical = canonicalUrl ?? new URL(Astro.url.pathname, siteUrl).href;
const absoluteOgImage = new URL(ogImage, siteUrl).href;

const localeMap: Record<string, string> = {
  en: 'en_US',
  zh: 'zh_CN',
};
const ogLocale = localeMap[lang] ?? 'en_US';

const defaultJsonLd = {
  '@context': 'https://schema.org',
  '@type': 'Church',
  name: 'FICCC — Fellowship of Ithaca Chinese Christians Church',
  description,
  url: canonical,
};

const structuredData = jsonLd ?? defaultJsonLd;
---

<title>{title}</title>
<meta name="description" content={description} />
<link rel="canonical" href={canonical} />

{alternateUrl && (
  <>
    <link rel="alternate" hreflang="en" href={lang === 'en' ? canonical : alternateUrl} />
    <link rel="alternate" hreflang="zh" href={lang === 'zh' ? canonical : alternateUrl} />
    <link rel="alternate" hreflang="x-default" href={lang === 'en' ? canonical : alternateUrl} />
  </>
)}

<!-- Open Graph -->
<meta property="og:title" content={title} />
<meta property="og:description" content={description} />
<meta property="og:url" content={canonical} />
<meta property="og:image" content={absoluteOgImage} />
<meta property="og:type" content={ogType} />
<meta property="og:locale" content={ogLocale} />

<!-- Twitter Card -->
<meta name="twitter:card" content="summary_large_image" />
<meta name="twitter:title" content={title} />
<meta name="twitter:description" content={description} />
<meta name="twitter:image" content={absoluteOgImage} />

<!-- JSON-LD Structured Data -->
<script type="application/ld+json" set:html={JSON.stringify(structuredData)} />

